def _run_trace(workspace: Path, trace_num: int, path_value: Optional[str] = None):
    tsh = workspace / "tsh"
    sdriver = workspace / "sdriver.pl"
    trace_file = workspace / "tests" / "public" / "data" / "shell" / f"trace{trace_num:02d}.txt"

    if not tsh.exists():
        success, error = compile_c_program(workspace)
        assert success, error

    if USE_DOCKER:
        from framework.docker_utils import run_bash_in_container

        trace_dir = str((workspace / "tests" / "public" / "data" / "shell").resolve())
        base_cmd = f"/usr/bin/perl ./sdriver.pl -t /traces/trace{trace_num:02d}.txt -s ./tsh -a -p"
        script = base_cmd if path_value is None else f'export PATH="{path_value}"; {base_cmd}'
        returncode, stdout, stderr = run_bash_in_container(
            image=DOCKER_IMAGE,
            script=script,
            workspace=workspace,
            timeout=30,
            memory="4g",
            cpus="2",
            network="none",
            extra_volumes={trace_dir: "/traces:ro"},
        )
        return returncode, (stdout or "") + (stderr or "")

