        capture_output=True,
        text=True,
        timeout=30,
        cwd=str(workspace),
        env=env,
    )
    return result.returncode, result.stdout + result.stderr


def test_trace14_error_messages(workspace):
    workspace = Path(workspace)
    returncode, output = _run_trace(workspace, 14)

    if returncode < 0:
        return make_test_result(False, "no crash", f"return code {returncode}", None)

    required = [
        "./bogus: Command not found.",
        "fg command requires PID or %jobid argument",
        "bg command requires PID or %jobid argument",
        "fg: argument must be a PID or %jobid",
        "bg: argument must be a PID or %jobid",
        "(9999999): No such process",
        "%2: No such job",
    ]
    for message in required:
        if message not in output:
            return make_test_result(False, message, output[:400], None)

    return make_test_result(True, "passed", "trace14 diagnostics matched", None)


def test_path_empty_entry_searches_current_directory(workspace):
    workspace = Path(workspace)

    for trace_num, path_value in [(20, ""), (21, ":/usr/bin"), (22, "/usr/bin::/bin"), (23, "/usr/bin:")]:
